toolArgs.file_text:
@page "/account/login"
@using Microsoft.AspNetCore.Identity
@using Microsoft.AspNetCore.Authentication
@layout sv_ccf29a48881c47b9b6be86c6e080d004.Components.Layout.MainLayout

<PageTitle>Login</PageTitle>

<div class="row justify-content-center mt-5">
    <div class="col-md-4">
        <h3 class="text-center mb-4">Sign In</h3>

        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        <form method="post" @formname="login" @onsubmit="HandleLogin">
            <AntiforgeryToken />
            <div class="mb-3">
                <label for="email" class="form-label">Email</label>
                <input type="email" class="form-control" id="email" @bind="email" required />
            </div>
            <div class="mb-3">
                <label for="password" class="form-label">Password</label>
                <input type="password" class="form-control" id="password" @bind="password" required />
            </div>
            <button type="submit" class="btn btn-primary w-100">Login</button>
        </form>
    </div>
</div>

@code {
    [Inject] private SignInManager<IdentityUser> SignInManager { get; set; } = default!;
    [Inject] private UserManager<IdentityUser> UserManager { get; set; } = default!;
    [Inject] private NavigationManager Navigation { get; set; } = default!;
    [Inject] private IHttpContextAccessor HttpContextAccessor { get; set; } = default!;

    [SupplyParameterFromForm] private string email { get; set; } = "";
    [SupplyParameterFromForm] private string password { get; set; } = "";
    [SupplyParameterFromQuery] private string? returnUrl { get; set; }

    private string? errorMessage;

    private async Task HandleLogin()
    {
        var user = await UserManager.FindByEmailAsync(email);
        if (user is null)
        {
            errorMessage = "Invalid email or password.";
            return;
        }

        var result = await SignInManager.CheckPasswordSignInAsync(user, password, lockoutOnFailure: false);
        if (!result.Succeeded)
        {
            errorMessage = "Invalid email or password.";
            return;
        }

        var httpContext = HttpContextAccessor.HttpContext!;
        var principal = await SignInManager.CreateUserPrincipalAsync(user);
        await httpContext.SignInAsync(
            IdentityConstants.ApplicationScheme,
            principal);

        var target = string.IsNullOrEmpty(returnUrl) ? "/" : returnUrl;
        Navigation.NavigateTo(target, forceLoad: true);
    }
}

