@page "/account/logout"
@using Microsoft.AspNetCore.Authentication
@using Microsoft.AspNetCore.Identity
@layout sv_ccf29a48881c47b9b6be86c6e080d004.Components.Layout.MainLayout

<PageTitle>Logout</PageTitle>

<div class="text-center mt-5">
    <h3>Sign Out</h3>
    <form method="post" @formname="logout" @onsubmit="HandleLogout">
        <AntiforgeryToken />
        <button type="submit" class="btn btn-outline-secondary mt-3">Confirm Logout</button>
    </form>
</div>

@code {
    [Inject] private IHttpContextAccessor HttpContextAccessor { get; set; } = default!;
    [Inject] private NavigationManager Navigation { get; set; } = default!;

    private async Task HandleLogout()
    {
        var httpContext = HttpContextAccessor.HttpContext!;
        await httpContext.SignOutAsync(IdentityConstants.ApplicationScheme);
        Navigation.NavigateTo("/", forceLoad: true);
    }
}

